# Generated by openai (o3-mini)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any
    parameters {
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'URL to the pre-built artifact')
        string(name: 'DESTINATION_SERVER', defaultValue: '', description: 'Production server hostname or IP')
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/app', description: 'Deployment path on the production server')
    }
    stages {
        stage('Download Artifact') {
            steps {
                script {
                    echo "Downloading artifact from: ${params.ARTIFACT_URL}"
                    // Download the artifact using curl (change to wget if preferred)
                    sh "curl -L -o artifact.jar '${params.ARTIFACT_URL}'"
                }
            }
        }
        stage('Deploy to Production') {
            steps {
                script {
                    echo "Deploying artifact to server: ${params.DESTINATION_SERVER}"
                    // Deploy using scp; ensure SSH keys or credentials are properly set up in Jenkins
                    sh "scp artifact.jar ${params.DESTINATION_SERVER}:${params.DEPLOY_PATH}/artifact.jar"
                }
            }
        }
    }
    post {
        success {
            echo "Deployment completed successfully."
        }
        failure {
            echo "Deployment failed."
        }
    }
}